// App.js
import React, { useEffect, useState } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
  Platform,
} from 'react-native';

const Stack = createNativeStackNavigator();
const rnBiometrics = new ReactNativeBiometrics({ allowDeviceCredentials: true });

const AUTH_KEY = '@authenticated';
const BIOMETRIC_ENABLED_KEY = '@biometric_enabled';

// ---------- Auth Service ----------
const AuthService = {
  async isAuthenticated() {
    try {
      const value = await AsyncStorage.getItem(AUTH_KEY);
      return value === 'true';
    } catch {
      return false;
    }
  },

  async setAuthenticated(value) {
    try {
      await AsyncStorage.setItem(AUTH_KEY, value ? 'true' : 'false');
    } catch (error) {
      console.error('Error setting auth state:', error);
    }
  },

  async isBiometricEnabled() {
    try {
      const value = await AsyncStorage.getItem(BIOMETRIC_ENABLED_KEY);
      return value === 'true';
    } catch {
      return false;
    }
  },

  async setBiometricEnabled(value) {
    try {
      await AsyncStorage.setItem(BIOMETRIC_ENABLED_KEY, value ? 'true' : 'false');
    } catch (error) {
      console.error('Error setting biometric state:', error);
    }
  },

  async checkBiometricAvailability() {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      return { available, biometryType };
    } catch {
      return { available: false, biometryType: null };
    }
  },

  async authenticateWithBiometrics() {
    try {
      const { available, biometryType } = await this.checkBiometricAvailability();

      if (!available) {
        return { success: false, error: 'Biometrics not available' };
      }

      let promptMessage = 'Authenticate to continue';
      if (biometryType === BiometryTypes.FaceID) {
        promptMessage = 'Authenticate with Face ID';
      } else if (biometryType === BiometryTypes.TouchID || biometryType === BiometryTypes.Biometrics) {
        promptMessage = 'Authenticate with Fingerprint';
      }

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Use Password',
      });

      if (success) {
        await this.setAuthenticated(true);
        await this.setBiometricEnabled(true);
        return { success: true };
      }

      return { success: false, error: 'Authentication cancelled' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  },

  async authenticateWithPassword(username, password) {
    // Replace with your actual API authentication logic
    if (username && password && password.length >= 6) {
      await this.setAuthenticated(true);
      return { success: true };
    }
    return { success: false, error: 'Invalid credentials' };
  },

  async logout() {
    await this.setAuthenticated(false);
  },

  async createBiometricKeys() {
    try {
      const { publicKey } = await rnBiometrics.createKeys();
      return publicKey;
    } catch (error) {
      console.error('Error creating biometric keys:', error);
      return null;
    }
  },

  async deleteBiometricKeys() {
    try {
      await rnBiometrics.deleteKeys();
      await this.setBiometricEnabled(false);
    } catch (error) {
      console.error('Error deleting biometric keys:', error);
    }
  },
};

// ---------- Login Screen ----------
function LoginScreen({ navigation }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);
  const [biometricLoading, setBiometricLoading] = useState(true);

  useEffect(() => {
    checkBiometrics();
  }, []);

  const checkBiometrics = async () => {
    setBiometricLoading(true);
    const { available, biometryType: type } = await AuthService.checkBiometricAvailability();
    setBiometricAvailable(available);
    setBiometryType(type);
    setBiometricLoading(false);

    // Auto-prompt biometrics if previously enabled
    if (available) {
      const biometricEnabled = await AuthService.isBiometricEnabled();
      if (biometricEnabled) {
        handleBiometricAuth();
      }
    }
  };

  const handleBiometricAuth = async () => {
    setLoading(true);
    const result = await AuthService.authenticateWithBiometrics();
    setLoading(false);

    if (result.success) {
      navigation.reset({
        index: 0,
        routes: [{ name: 'Home' }],
      });
    } else if (result.error !== 'Authentication cancelled') {
      Alert.alert('Authentication Failed', result.error);
    }
  };

  const handlePasswordLogin = async () => {
    if (!username.trim()) {
      Alert.alert('Error', 'Please enter your username');
      return;
    }
    if (!password.trim()) {
      Alert.alert('Error', 'Please enter your password');
      return;
    }

    setLoading(true);
    const result = await AuthService.authenticateWithPassword(username, password);
    setLoading(false);

    if (result.success) {
      // Offer biometric enrollment if available
      if (biometricAvailable) {
        const biometricEnabled = await AuthService.isBiometricEnabled();
        if (!biometricEnabled) {
          promptBiometricEnrollment();
          return;
        }
      }
      navigation.reset({
        index: 0,
        routes: [{ name: 'Home' }],
      });
    } else {
      Alert.alert('Login Failed', result.error || 'Invalid credentials. Password must be at least 6 characters.');
    }
  };

  const promptBiometricEnrollment = () => {
    const biometricName = getBiometricName();
    Alert.alert(
      `Enable ${biometricName}`,
      `Would you like to enable ${biometricName} for faster login next time?`,
      [
        {
          text: 'Not Now',
          style: 'cancel',
          onPress: () => {
            navigation.reset({
              index: 0,
              routes: [{ name: 'Home' }],
            });
          },
        },
        {
          text: 'Enable',
          onPress: async () => {
            await AuthService.createBiometricKeys();
            await AuthService.setBiometricEnabled(true);
            navigation.reset({
              index: 0,
              routes: [{ name: 'Home' }],
            });
          },
        },
      ]
    );
  };

  const getBiometricName = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return 'Face ID';
      case BiometryTypes.TouchID:
        return 'Touch ID';
      case BiometryTypes.Biometrics:
        return 'Fingerprint';
      default:
        return 'Biometric Authentication';
    }
  };

  const getBiometricIcon = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return '👤';
      case BiometryTypes.TouchID:
      case BiometryTypes.Biometrics:
        return '👆';
      default:
        return '🔐';
    }
  };

  if (biometricLoading) {
    return (
      <View style={styles.loadingContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.headerContainer}>
        <Text style={styles.appIcon}>🔒</Text>
        <Text style={styles.title}>Welcome Back</Text>
        <Text style={styles.subtitle}>Sign in to continue</Text>
      </View>

      {biometricAvailable && (
        <TouchableOpacity
          style={styles.biometricButton}
          onPress={handleBiometricAuth}
          disabled={loading}
        >
          <Text style={styles.biometricIcon}>{getBiometricIcon()}</Text>
          <Text style={styles.biometricButtonText}>
            Sign in with {getBiometricName()}
          </Text>
        </TouchableOpacity>
      )}

      {biometricAvailable && (
        <View style={styles.dividerContainer}>
          <View style={styles.dividerLine} />
          <Text style={styles.dividerText}>OR</Text>
          <View style={styles.dividerLine} />
        </View>
      )}

      <View style={styles.formContainer}>
        <View style={styles.inputContainer}>
          <Text style={styles.inputLabel}>Username</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your username"
            placeholderTextColor="#999"
            value={username}
            onChangeText={setUsername}
            autoCapitalize="none"
            autoCorrect={false}
            editable={!loading}
          />
        </View>

        <View style={styles.inputContainer}>
          <Text style={styles.inputLabel}>Password</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your password"
            placeholderTextColor="#999"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            editable={!loading}
          />
        </View>

        <TouchableOpacity
          style={[styles.loginButton, loading && styles.loginButtonDisabled]}
          onPress={handlePasswordLogin}
          disabled={loading}
        >
          {loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In with Password</Text>
          )}
        </TouchableOpacity>
      </View>

      {!biometricAvailable && (
        <Text style={styles.noBiometricText}>
          Biometric authentication is not available on this device.
          {Platform.OS === 'ios'
            ? ' Please use Face ID/Touch ID settings to enable it.'
            : ' Please set up fingerprint in device settings.'}
        </Text>
      )}
    </View>
  );
}

// ---------- Home Screen ----------
function HomeScreen({ navigation }) {
  const [biometricEnabled, setBiometricEnabled] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    const enabled = await AuthService.isBiometricEnabled();
    setBiometricEnabled(enabled);
    const { available, biometryType: type } = await AuthService.checkBiometricAvailability();
    setBiometricAvailable(available);
    setBiometryType(type);
  };

  const getBiometricName = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return 'Face ID';
      case BiometryTypes.TouchID:
        return 'Touch ID';
      case BiometryTypes.Biometrics:
        return 'Fingerprint';
      default:
        return 'Biometric Authentication';
    }
  };

  const toggleBiometric = async () => {
    if (biometricEnabled) {
      await AuthService.deleteBiometricKeys();
      setBiometricEnabled(false);
      Alert.alert('Disabled', `${getBiometricName()} has been disabled.`);
    } else {
      const result = await AuthService.authenticateWithBiometrics();
      if (result.success) {
        await AuthService.createBiometricKeys();
        await AuthService.setBiometricEnabled(true);
        setBiometricEnabled(true);
        Alert.alert('Enabled', `${getBiometricName()} has been enabled for future logins.`);
      }
    }
  };

  const handleLogout = async () => {
    Alert.alert('Logout', 'Are you sure you want to logout?', [
      { text: 'Cancel', style: 'cancel' },
      {
        text: 'Logout',
        style: 'destructive',
        onPress: async () => {
          await AuthService.logout();
          navigation.reset({
            index: 0,
            routes: [{ name: 'Login' }],
          });
        },
      },
    ]);
  };

  return (
    <View style={styles.container}>
      <View style={styles.homeHeader}>
        <Text style={styles.homeIcon}>✅</Text>
        <Text style={styles.homeTitle}>Authenticated!</Text>
        <Text style={styles.homeSubtitle}>
          You are securely logged in
        </Text>
      </View>

      <View style={styles.settingsContainer}>
        <Text style={styles.settingsTitle}>Security Settings</Text>

        {biometricAvailable && (
          <TouchableOpacity
            style={styles.settingsRow}
            onPress={toggleBiometric}
          >
            <View style={styles.settingsRowLeft}>
              <Text style={styles.settingsRowIcon}>
                {biometryType === BiometryTypes.FaceID ? '👤' : '👆'}
              </Text>
              <View>
                <Text style={styles.settingsRowTitle}>{getBiometricName()}</Text>
                <Text style={styles.settingsRowSubtitle}>
                  {biometricEnabled ? 'Enabled' : 'Disabled'}
                </Text>
              </View>
            </View>
            <View
              style={[
                styles.toggleIndicator,
                biometricEnabled && styles.toggleIndicatorActive,
              ]}
            >
              <Text style={styles.toggleText}>
                {biometricEnabled ? 'ON' : 'OFF'}
              </Text>
            </View>
          </TouchableOpacity>
        )}

        {!biometricAvailable && (
          <View style={styles.settingsRow}>
            <View style={styles.settingsRowLeft}>
              <Text style={styles.settingsRowIcon}>⚠️</Text>
              <View>
                <Text style={styles.settingsRowTitle}>Biometrics</Text>
                <Text style={styles.settingsRowSubtitle}>
                  Not available on this device
                </Text>
              </View>
            </View>
          </View>
        )}
      </View>

      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.logoutButtonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
}

// ---------- Splash / Auth Check Screen ----------
function SplashScreen({ navigation }) {
  useEffect(() => {
    checkAuth();
  }, []);

  const checkAuth = async () => {
    const isAuth = await AuthService.isAuthenticated();
    const biometricEnabled = await AuthService.isBiometricEnabled();

    if (isAuth && biometricEnabled) {
      // Re-verify with biometrics before granting access
      const result = await AuthService.authenticateWithBiometrics();
      if (result.success) {
        navigation.reset({
          index: 0,
          routes: [{ name: 'Home' }],
        });
      } else {
        navigation.reset({
          index: 0,
          routes: [{ name: 'Login' }],
        });
      }
    } else if (isAuth) {
      // Authenticated but no biometric, go directly to home
      navigation.reset({
        index: 0,
        routes: [{ name: 'Home' }],
      });
    } else {
      navigation.reset({
        index: 0,
        routes: [{ name: 'Login' }],
      });
    }
  };

  return (
    <View style={styles.loadingContainer}>
      <Text style={styles.splashIcon}>🔐</Text>
      <ActivityIndicator size="large" color="#007AFF" style={{ marginTop: 20 }} />
      <Text style={styles.splashText}>Checking authentication...</Text>
    </View>
  );
}

// ---------- App ----------
export default function App() {
  return (
    <NavigationContainer>
      <Stack.Navigator
        screenOptions={{
          headerShown: false,
        }}
      >
        <Stack.Screen name="Splash" component={SplashScreen} />
        <Stack.Screen name="Login" component={LoginScreen} />
        <Stack.Screen name="Home" component={HomeScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

